"use client";

import { motion } from "framer-motion";
import { ArrowUpRight } from "lucide-react";

const posts = [
    {
        title: "Why Scaling Microservices is Harder Than You Think",
        date: "Feb 24, 2026",
        readTime: "6 min read",
        description: "Discussing common pitfalls in distributed systems, including split-brain scenarios and network partitions.",
        link: "#"
    },
    {
        title: "Optimizing DynamoDB for High-Throughput Workloads",
        date: "Jan 12, 2026",
        readTime: "8 min read",
        description: "A deep dive into partition keys, GSI overloading, and handling hot partitions in DynamoDB.",
        link: "#"
    },
    {
        title: "From React to Rust: A Backend Journey",
        date: "Dec 05, 2025",
        readTime: "5 min read",
        description: "How transitioning some of our core BFF logic to memory-safe languages improved latency.",
        link: "#"
    }
];

export function Blog() {
    return (
        <section id="blog" className="py-24 px-6 md:px-12 max-w-4xl mx-auto">
            <motion.div
                initial={{ opacity: 0, y: 40 }}
                whileInView={{ opacity: 1, y: 0 }}
                viewport={{ once: true, margin: "-100px" }}
                transition={{ duration: 0.8, ease: "easeOut" }}
            >
                <div className="flex justify-between items-end mb-12">
                    <h2 className="text-4xl font-bold tracking-tight">Writing</h2>
                    <a href="#" className="hidden md:flex items-center text-sm font-medium hover:text-neutral-500 transition-colors">
                        View all posts <ArrowUpRight className="ml-1 w-4 h-4" />
                    </a>
                </div>

                <div className="space-y-8 text-left border-t border-neutral-200 dark:border-neutral-800 pt-8">
                    {posts.map((post, index) => (
                        <motion.article
                            key={post.title}
                            initial={{ opacity: 0, y: 10 }}
                            whileInView={{ opacity: 1, y: 0 }}
                            viewport={{ once: true }}
                            transition={{ duration: 0.5, delay: index * 0.1 }}
                            className="group flex flex-col md:flex-row md:items-baseline md:justify-between py-4"
                        >
                            <div className="flex-1 md:pr-8">
                                <a href={post.link} className="block">
                                    <h3 className="text-xl font-bold tracking-tight group-hover:text-neutral-500 transition-colors">
                                        {post.title}
                                    </h3>
                                    <p className="mt-3 text-neutral-600 dark:text-neutral-400 font-light leading-relaxed">
                                        {post.description}
                                    </p>
                                </a>
                            </div>
                            <div className="mt-4 md:mt-0 md:text-right shrink-0">
                                <p className="text-sm font-medium text-neutral-800 dark:text-neutral-300">
                                    {post.date}
                                </p>
                                <p className="text-sm text-neutral-500 dark:text-neutral-500 mt-1">
                                    {post.readTime}
                                </p>
                            </div>
                        </motion.article>
                    ))}
                </div>
            </motion.div>
        </section>
    );
}
